func settingsTabButtonClass(active state.SettingsTab, tab state.SettingsTab) string {
	class := "rounded-md px-3 py-2 text-center text-sm transition hover:text-[var(--foreground)]"
	if active == tab {
		return class + " bg-[var(--background)] text-[var(--foreground)] shadow-sm"
	}
	return class + " text-[var(--muted-foreground)]"
}

func settingsTabCommand(tab state.SettingsTab) string {
	return "@discobotCommand(" + strconv.Quote("/ui/commands/settings/tabs/"+string(tab)) + ", {method: 'POST'})"
}

func settingsSwitchClass(checked bool) string {
	class := "relative inline-flex h-6 w-11 rounded-full border border-transparent transition"
	if checked {
		return class + " bg-[var(--primary)]"
	}
	return class + " bg-[var(--muted)]"
}

func settingsSwitchThumbClass(checked bool) string {
	class := "absolute top-0.5 h-5 w-5 rounded-full bg-[var(--background)] shadow transition"
	if checked {
		return class + " left-5"
	}
	return class + " left-0.5"
}

func settingsCredentialStatus(configured bool) string {
	if configured {
		return "Configured"
	}
	return "Missing"
}

func settingsCredentialStatusClass(configured bool) string {
	class := "rounded-full px-2 py-1 text-xs"
	if configured {
		return class + " bg-[var(--diff-add-line)] text-[var(--foreground)]"
	}
	return class + " bg-[var(--muted)] text-[var(--muted-foreground)]"
}

func settingsCredentialAction(configured bool) string {
	if configured {
		return "Update"
	}
	return "Add"
}

